tactics.medic:
class Tactic:
    def __init__(self):
        pass
    def tick(self, me, world):
        allies = world.visible_allies()
        for ally in allies:
            if ally.hp < ally.max_hp and me.can_heal(ally):
                return me.heal(ally)
        target = world.nearest_visible_enemy()
        if target and me.cooldown == 0 and me.move_cd == 0:
            return me.move_toward(target.pos)
        return me.move_toward(world.enemy_spawn)

